  describe('notification delivery ordering', () => {
    it('should deliver notifications in order even when adapter is slow', async () => {
      const deliveryOrder: string[] = [];

      // Adapter where the first call takes longer than the second,
      // which would cause out-of-order delivery without a queue.
      let callCount = 0;
      const slowAdapter: NotificationAdapter = {
        channel: 'email' as const,
        async send(payload: NotificationPayload): Promise<NotificationResult> {
          callCount++;
          const delay = callCount === 1 ? 50 : 10;
          await new Promise((resolve) => setTimeout(resolve, delay));
          deliveryOrder.push(payload.subject);
          return { success: true, channel: 'email', deliveredAt: new Date() };
        },
      };

      const freshEventBus = new EventBus();
      statusChangeCallbacks.clear();
      const orderedService = new NotificationService(freshEventBus, [slowAdapter]);
      resetNotificationIdCounter();

      const orderCreatedEvent: OrderCreatedEvent = {
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
          total: 10,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      const statusChangedEvent: OrderStatusChangedEvent = {
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 10,
          status: 'confirmed',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      };

      // Fire both events concurrently (don't await the first before the second)
      const p1 = freshEventBus.emit(orderCreatedEvent);
      const p2 = freshEventBus.emit(statusChangedEvent);
      await Promise.all([p1, p2]);

      // Despite the first adapter call being slower, order should be preserved
      expect(deliveryOrder).toHaveLength(2);
      expect(deliveryOrder[0]).toContain('Order Confirmation');
      expect(deliveryOrder[1]).toContain('Order Update');

      // Records should also be in order
      const records = orderedService.getNotificationRecords();
      expect(records).toHaveLength(2);
      expect(records[0]!.payload.type).toBe('order_confirmation');
      expect(records[1]!.payload.type).toBe('order_status_update');
    });
  });
});

